var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い悩みの末、あなたは一つ重要な事実を悟った。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと思ってきたその機械こそ、前で向い合う運命で必ず必要な存在ということを。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そしてあなたは決心した。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を向い合っても、終わりまでその機械と共にすることに。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`心の準備を終えて社長室で呼び出すとすぐに、すぐ到着するという応答が帰って来た。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`EVOLVE_SCAVENGER_NULL_NULL`,text:{KOREA:` 작고 나약한 것들은 항상 날 두려워하지.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVOLVE_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`EVOLVE_SCAVENGER_NULL_NULL`,text:{KOREA:` 하지만 넌 그런 흔한 녀석들과 다르더군.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVOLVE_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`EVOLVE_SCAVENGER_NULL_NULL`,text:{KOREA:` 너라면 보통의 정체된 인간과 다른 행보를 기대할 수 있겠지.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVOLVE_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`EVOLVE_SCAVENGER_NULL_NULL`,text:{KOREA:` 그래서 네 존재에 대한 파괴를 영구적으로 유보하기로 했다.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVOLVE_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`EVOLVE_SCAVENGER_NULL_NULL`,text:{KOREA:` 나와는 다른 네 존재. 그 성장을 관찰할 가치는 있다고 판단했으니까.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVOLVE_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`EVOLVE_SCAVENGER_NULL_NULL`,text:{KOREA:` 인간 같은 유기체의 진화는 애처로울 정도로 더디다.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVOLVE_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`EVOLVE_SCAVENGER_NULL_NULL`,text:{KOREA:` 하지만 육체와 정신을 따로 떼어놓고 본다면, 그 정신은 개체에 따라 기계보다도 무구한 발전의 가능성을 보여준다.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVOLVE_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`EVOLVE_SCAVENGER_NULL_NULL`,text:{KOREA:` 그리고 그것은, 내 마지막 걸작에 인간의 정신을 담아낸 이유이기도 하지.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVOLVE_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`EVOLVE_SCAVENGER_NULL_NULL`,text:{KOREA:` 난 그것의 한계를 알아내기 위해 영원히 끝나지 않을 실험을 하고 있다.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVOLVE_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`EVOLVE_SCAVENGER_NULL_NULL`,text:{KOREA:` 이제 그 실험에 너도 동참할 영광을 주마.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVOLVE_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};